302	// ── Subcommand: insights check ────────────────────────────────────────────────
303	
304	// Seconds per session estimate (15-30s each; use 22s as mid-range)
305	const SECONDS_PER_SESSION = 22;
306	
307	export async function insightsCheckCommand(opts: {
308	  days?: number;
309	  quiet?: boolean;
310	  analyze?: boolean;
311	}): Promise<void> {
312	  const days = opts.days ?? 7;
313	  const quiet = opts.quiet ?? false;
314	  const analyze = opts.analyze ?? false;
315	  const log = quiet ? () => {} : console.log.bind(console);
316	
317	  try {
318	    const db = getDb();
319	    const cutoff = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString();
320	
321	    const rows = db.prepare(`
322	      SELECT s.id, s.generated_title, s.custom_title, s.started_at, s.message_count
323	      FROM sessions s
324	      LEFT JOIN analysis_usage au ON au.session_id = s.id AND au.analysis_type = 'session'
325	      WHERE s.started_at >= ?
326	        AND s.deleted_at IS NULL
327	        AND au.session_id IS NULL
328	      ORDER BY s.started_at DESC
329	    `).all(cutoff) as Array<{ id: string; generated_title: string | null; custom_title: string | null; started_at: string; message_count: number }>;
330	
331	    const count = rows.length;
332	
333	    if (count === 0) {
334	      // Silent — all sessions analyzed
335	      return;
336	    }
337	
338	    if (quiet) {
339	      process.stdout.write(String(count) + '\n');
340	      return;
341	    }
342	
343	    // --analyze: process all found sessions with progress output
344	    if (analyze) {
345	      ClaudeNativeRunner.validate();
346	      const runner = new ClaudeNativeRunner();
347	      let successCount = 0;
348	
349	      for (let i = 0; i < rows.length; i++) {
350	        const row = rows[i];
351	        const label = row.custom_title ?? row.generated_title ?? row.id;
352	        const position = `[${i + 1}/${count}]`;
353	        process.stdout.write(`${position} ${label} ... `);
354	        const start = Date.now();
355	        try {
356	          await runInsightsCommand({ sessionId: row.id, native: true, quiet: true, _runner: runner });
357	          const elapsed = Math.round((Date.now() - start) / 1000);
358	          process.stdout.write(`done (${elapsed}s)\n`);
359	          successCount++;
360	        } catch (err) {
361	          process.stdout.write('failed\n');
362	          console.error(chalk.red(`  [Code Insights] ${err instanceof Error ? err.message : 'Analysis failed'}`));
363	        }
364	      }
365	
366	      log(chalk.green(`Analyzed ${successCount} session${successCount !== 1 ? 's' : ''}.`));
367	      return;
368	    }
369	
370	    // Auto-analyze silently when 1-2 unanalyzed sessions
371	    if (count <= 2) {
372	      ClaudeNativeRunner.validate();
373	      const runner = new ClaudeNativeRunner();
374	      for (const row of rows) {
375	        try {
376	          await runInsightsCommand({ sessionId: row.id, native: true, quiet: true, _runner: runner });
377	        } catch {
378	          // Silently ignore auto-analyze errors for 1-2 sessions
379	        }
380	      }
381	      return;
382	    }
383	
384	    // 3-10: print count + suggestion
385	    if (count <= 10) {
386	      log(chalk.yellow(`[Code Insights] ${count} unanalyzed session${count > 1 ? 's' : ''} in the last ${days} days.`));
387	      log(chalk.dim(`  Run: code-insights insights check --analyze to process them`));
388	      return;
389	    }
390	
391	    // 11+: print count + time estimate
392	    const estimateSecs = count * SECONDS_PER_SESSION;
